    36→const minWatchProgressInterval = 100 * time.Millisecond
    37→
    38→type watchServer struct {
    39→	lg *zap.Logger
    40→
    41→	clusterID int64
    42→	memberID  int64
    43→
    44→	maxRequestBytes int
    45→
    46→	sg        etcdserver.RaftStatusGetter
