n\t\t}\n\t\tif err != nil {\n\t\t\treturn err\n\t\t}\n\n\t\tswitch uv := req.RequestUnion.(type) {\n\t\tcase *pb.WatchRequest_CreateRequest:\n\t\t\tif uv.CreateRequest == nil {\n\t\t\t\tbreak\n\t\t\t}\n\n\t\t\tcreq := uv.CreateRequest\n\t\t\tif len(creq.Key) == 0 {\n\t\t\t\t// \\x00 is the smallest key\n\t\t\t\tcreq.Key = []byte{0}\n\t\t\t}\n\t\t\tif len(creq.RangeEnd) == 0 {\n\t\t\t\t// force nil since watchstream.Watch distinguishes\n\t\t\t\t// between nil and []byte{} for single key / >=\n\t\t\t\tcreq.RangeEnd = nil\n\t\t\t}\n\t\t\tif len(creq.RangeEnd) == 1 && creq.RangeEnd[0] == 0 {\n\t\t\t\t// support  >= key queries\n\t\t\t\tcreq.RangeEnd = []byte{}\n\t\t\t}\n\n\t\t\terr := sws.isWatchPermitted(creq)\n\t\t\tif err != nil {\n\t\t\t\tvar cancelReason string\n\t\t\t\tswitch err {\n\t\t\t\tcase auth.ErrInvalidAuthToken:\n\t\t\t\t\tcancelReason = rpctypes.ErrGRPCInvalidAuthToken.Error()\n\t\t\t\tcase auth.ErrAuthOldRevision:\n\t\t\t\t\tcancelReason = rpctypes.ErrGRPCAuthOldRevision.Error()\n\t\t\t\tcase auth.ErrUserEmpty:\n\t\t\t\t\tcancelReason = rpctypes.ErrGRPCUserEmpty.Error()\n\t\t\t\tdefault:\n\t\t\t\t\tif err != auth.ErrPermissionDenied {\n\t\t\t\t\t\tsws.lg.Error(\"unexpected error code\", zap.Error(err))\n\t\t\t\t\t}\n\t\t\t\t\tcancelReason = rpctypes.ErrGRPCPermissionDenied.Error()\n\t\t\t\t}\n\n\t\t\t\twr := &pb.WatchResponse{\n\t\t\t\t\tHeader:       sws.newResponseHeader(sws.watchStream.Rev()),\n\t\t\t\t\tWatchId:      clientv3.InvalidWatchID,\n\t\t\t\t\tCanceled:     true,\n\t\t\t\t\tCreated:      true,\n\t\t\t\t\tCancelReason: cancelReason,\n\t\t\t\t}\n\n\t\t\t\tselect {\n\t\t\t\tcase sws.ctrlStream <- wr:\n\t\t\t\t\tcontinue\n\t\t\t\tcase <-sws.closec:\n\t\t\t\t\treturn nil\n\t\t\t\t}\n\t\t\t}\n\n\t\t\tfilters := FiltersFromRequest(creq)\n\n\t\t\twsrev := sws.watchStream.Rev()\n\t\t\trev := creq.StartRevision\n\t\t\tif rev == 0 {\n\t\t\t\trev = wsrev + 1\n\t\t\t}\n\t\t\tid, err := sws.watchStream.Watch(mvcc.WatchID(creq.WatchId), creq.Key, creq.RangeEnd, rev, filters...)\n\t\t\tif err == nil {\n\t\t\t\tsws.mu.Lock()\n\t\t\t\tif creq.ProgressNotify {\n\t\t\t\t\tsws.progress[id] = true\n\t\t\t\t}\n\t\t\t\tif creq.PrevKv {\n\t\t\t\t\tsws.prevKV[id] = true\n\t\t\t\t}\n\t\t\t\tif creq.Fragment {\n\t\t\t\t\tsws.fragment[id] = true\n\t\t\t\t}\n\t\t\t\tsws.mu.Unlock()\n\t\t\t} else {\n\t\t\t\tid = clientv3.InvalidWatchID\n\t\t\t}\n\n\t\t\twr := &pb.WatchResponse{\n\t\t\t\tHeader:   sws.newResponseHeader(wsrev),\n\t\t\t\tWatchId:  int64(id),\n\t\t\t\tCreated:  true,\n\t\t\t\tCanceled: err != nil,\n\t\t\t}\n\t\t\tif err != nil {\n\t\t\t\twr.CancelReason = err.Error()\n\t\t\t}\n\t\t\tselect {\n\t\t\tcase sws.ctrlStream <- wr:\n\t\t\tcase <-sws.closec:\n\t\t\t\treturn nil\n\t\t\t}\n\n\t\tcase *pb.WatchRequest_CancelRequest:\n\t\t\tif uv.CancelRequest != nil {\n\t\t\t\tid := uv.CancelRequest.WatchId\n\t\t\t\terr := sws.watchStream.Cancel(mvcc.WatchID(id))\n\t\t\t\tif err == nil {\n\t\t\t\t\twr := &pb.WatchResponse{\n\t\t\t\t\t\tHeader:   sws.newResponseHeader(sws.watchStream.Rev()),\n\t\t\t\t\t\tWatchId:  id,\n\t\t\t\t\t\tCanceled: true,\n\t\t\t\t\t}\n\t\t\t\t\tselect {\n\t\t\t\t\tcase sws.ctrlStream <- wr:\n\t\t\t\t\tcase <-sws.closec:\n\t\t\t\t\t\treturn nil\n\t\t\t\t\t}\n\n\t\t\t\t\tsws.mu.Lock()\n\t\t\t\t\tdelete(sws.progress, mvcc.WatchID(id))\n\t\t\t\t\tdelete(sws.prevKV, mvcc.WatchID(id))\n\t\t\t\t\tdelete(sws.fragment, mvcc.WatchID(id))\n\t\t\t\t\tsws.mu.Unlock()\n\t\t\t\t}\n\t\t\t}\n\t\tcase *pb.WatchRequest_ProgressRequest:\n\t\t\tif uv.ProgressRequest != nil {\n\t\t\t\tsws.mu.Lock()\n\t\t\t\tsws.watchStream.RequestProgressAll()\n\t\t\t\tsws.mu.Unlock()\n\t\t\t}\n\t\tdefault:\n\t\t\t// we probably should not shutdown the entire stream when\n\t\t\t// receive an valid command.\n\t\t\t// so just do nothing instead.\n\t\t\tcontinue\n\t\t}\n\t}\n}\n\nfunc (sws *serverWatchStream) sendLoop() {\n\t// watch ids that are currently active\n\tids := make(map[mvcc.WatchID]struct{})\n\t// watch responses pending on a watch id creation message\n\tpending := make(map[mvcc.WatchID][]*pb.WatchResponse)\n\n\tinterval := GetProgressReportInterval()\n\tprogressTicker := time.NewTicker(interval)\n\n\tdefer func() {\n\t\tprogressTicker.Stop()\n\t\t// drain the chan to clean up pending events\n\t\tfor ws := range sws.watchStream.Chan() {\n\t\t\tmvcc.ReportEventReceived(len(ws.Events))\n\t\t}\n\t\tfor _, wrs := range pending {\n\t\t\tfor _, ws := range wrs {\n\t\t\t\tmvcc.ReportEventReceived(len(ws.Events))\n\t\t\t}\n\t\t}\n\t}()\n\n\tfor {\n\t\tselect {\n\t\tcase wresp, ok := <-sws.watchStream.Chan():\n\t\t\tif !ok {\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\t// TODO: evs is []mvccpb.Event type\n\t\t\t// either return []*mvccpb.Event from the mvcc package\n\t\t\t// or define protocol buffer with []mvccpb.Event.\n\t\t\tevs := wresp.Events\n\t\t\tevents := make([]*mvccpb.Event, len(evs))\n\t\t\tsws.mu.RLock()\n\t\t\tneedPrevKV := sws.prevKV[wresp.WatchID]\n\t\t\tsws.mu.RUnlock()\n\t\t\tfor i := range evs {\n\t\t\t\tevents[i] = &evs[i]\n\t\t\t\tif needPrevKV && !IsCreateEvent(evs[i]) {\n\t\t\t\t\topt := mvcc.RangeOptions{Rev: evs[i].Kv.ModRevision - 1}\n\t\t\t\t\tr, err := sws.watchable.Range(context.TODO(), evs[i].Kv.Key, nil, opt)\n\t\t\t\t\tif err == nil && len(r.KVs) != 0 {\n\t\t\t\t\t\tevents[i].PrevKv = &(r.KVs[0])\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\n\t\t\tcanceled := wresp.CompactRevision != 0\n\t\t\twr := &pb.WatchResponse{\n\t\t\t\tHeader:          sws.newResponseHeader(wresp.Revision),\n\t\t\t\tWatchId:         int64(wresp.WatchID),\n\t\t\t\tEvents:          events,\n\t\t\t\tCompactRevision: wresp.CompactRevision,\n\t\t\t\tCanceled:        canceled,\n\t\t\t}\n\n\t\t\t// Progress notifications can have WatchID -1\n\t\t\t// if they announce on behalf of multiple watchers\n\t\t\tif wresp.WatchID != clientv3.InvalidWatchID {\n\t\t\t\tif _, okID := ids[wresp.WatchID]; !okID {\n\t\t\t\t\t// buffer if id not yet announced\n\t\t\t\t\twrs := append(pending[wresp.WatchID], wr)\n\t\t\t\t\tpending[wresp.WatchID] = wrs\n\t\t\t\t\tcontinue\n\t\t\t\t}\n\t\t\t}\n\n\t\t\tmvcc.ReportEventReceived(len(evs))\n\n\t\t\tsws.mu.RLock()\n\t\t\tfragmented, ok := sws.fragment[wresp.WatchID]\n\t\t\tsws.mu.RUnlock()\n\n\t\t\tvar serr error\n\t\t\tif !fragmented && !ok {\n\t\t\t\tserr = sws.gRPCStream.Send(wr)\n\t\t\t} else {\n\t\t\t\tserr = sendFragments(wr, sws.maxRequestBytes, sws.gRPCStream.Send)\n\t\t\t}\n\n\t\t\tif serr != nil {\n\t\t\t\tif isClientCtxErr(sws.gRPCStream.Context().Err(), serr) {\n\t\t\t\t\tsws.lg.Debug(\"failed to send watch response to gRPC stream\", zap.Error(serr))\n\t\t\t\t} else {\n\t\t\t\t\tsws.lg.Warn(\"failed to send watch response to gRPC stream\", zap.Error(serr))\n\t\t\t\t\tstreamFailures.WithLabelValues(\"send\", \"watch\").Inc()\n\t\t\t\t}\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tsws.mu.Lock()\n\t\t\tif len(evs) > 0 && sws.progress[wresp.WatchID] {\n\t\t\t\t// elide next progress update if sent a key update\n\t\t\t\tsws.progress[wresp.WatchID] = false\n\t\t\t}\n\t\t\tsws.mu.Unlock()\n\n\t\tcase c, ok := <-sws.ctrlStream:\n\t\t\tif !ok {\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tif err := sws.gRPCStream.Send(c); err != nil {\n\t\t\t\tif isClientCtxErr(sws.gRPCStream.Context().Err(), err) {\n\t\t\t\t\tsws.lg.Debug(\"failed to send watch control response to gRPC stream\", zap.Error(err))\n\t\t\t\t} else {\n\t\t\t\t\tsws.lg.Warn(\"failed to send watch control response to gRPC stream\", zap.Error(err))\n\t\t\t\t\tstreamFailures.WithLabelValues(\"send\", \"watch\").Inc()\n\t\t\t\t}\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\t// track id creation\n\t\t\twid := mvcc.WatchID(c.WatchId)\n\n\t\t\tif !(!(c.Canceled && c.Created) || wid == clientv3.InvalidWatchID) {\n\t\t\t\tpanic(fmt.Sprintf(\"unexpected watchId: %d, wanted: %d, since both 'Canceled' and 'Created' are true\", wid, clientv3.InvalidWatchID))\n\t\t\t}\n\n\t\t\tif c.Canceled && wid != clientv3.InvalidWatchID {\n\t\t\t\tdelete(ids, wid)\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tif c.Created {\n\t\t\t\t// flush buffered events\n\t\t\t\tids[wid] = struct{}{}\n\t\t\t\tfor _, v := range pending[wid] {\n\t\t\t\t\tmvcc.ReportEventReceived(len(v.Events))\n\t\t\t\t\tif err := sws.gRPCStream.Send(v); err != nil {\n\t\t\t\t\t\tif isClientCtxErr(sws.gRPCStream.Context().Err(), err) {\n\t\t\t\t\t\t\tsws.lg.Debug(\"failed to send pending watch response to gRPC stream\", zap.Error(err))\n\t\t\t\t\t\t} else {\n\t\t\t\t\t\t\tsws.lg.Warn(\"failed to send pending watch response to gRPC stream\", zap.Error(err))\n\t\t\t\t\t\t\tstreamFailures.WithLabelValues(\"send\", \"watch\").Inc()\n\t\t\t\t\t\t}\n\t\t\t\t\t\treturn\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\tdelete(pending, wid)\n\t\t\t}\n\n\t\tcase <-progressTicker.C:\n\t\t\tsws.mu.Lock()\n\t\t\tfor id, ok := range sws.progress {\n\t\t\t\tif ok {\n\t\t\t\t\tsws.watchStream.RequestProgress(id)\n\t\t\t\t}\n\t\t\t\tsws.progress[id] = true\n\t\t\t}\n\t\t\tsws.mu.Unlock()\n\n\t\tcase <-sws.closec:\n\t\t\treturn\n\t\t}\n\t}\n}\n\nfunc IsCreateEvent(e mvccpb.Event) bool {\n\treturn e.Type == mvccpb.PUT && e.Kv.CreateRevision == e.Kv.ModRevision\n}\n\nfunc sendFragments(\n\twr *pb.WatchResponse,\n\tmaxRequestBytes int,\n\tsendFunc func(*pb.WatchResponse) error) error {\n\t// no need to fragment if total request size is smaller\n\t// than max request limit or response contains only one event\n\tif wr.Size() < maxRequestBytes || len(wr.Events) < 2 {\n\t\treturn sendFunc(wr)\n\t}\n\n\tow := *wr\n\tow.Events = make([]*mvccpb.Event, 0)\n\tow.Fragment = true\n\n\tvar idx int\n\tfor {\n\t\tcur := ow\n\t\tfor _, ev := range wr.Events[idx:] {\n\t\t\tcur.Events = append(cur.Events, ev)\n\t\t\tif len(cur.Events) > 1 && cur.Size() >= maxRequestBytes {\n\t\t\t\tcur.Events = cur.Events[:len(cur.Events)-1]\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tidx++\n\t\t}\n\t\tif idx == len(wr.Events) {\n\t\t\t// last response has no more fragment\n\t\t\tcur.Fragment = false\n\t\t}\n\t\tif err := sendFunc(&cur); err != nil {\n\t\t\treturn err\n\t\t}\n\t\tif !cur.Fragment {\n\t\t\tbreak\n\t\t}\n\t}\n\treturn nil\n}\n\nfunc (sws *serverWatchStream) close() {\n\tsws.watchStream.Close()\n\tclose(sws.closec)\n\tsws.wg.Wait()\n}\n\nfunc (sws *serverWatchStream) newResponseHeader(rev int64) *pb.ResponseHeader {\n\treturn &pb.ResponseHeader{\n\t\tClusterId: uint64(sws.clusterID),\n\t\tMemberId:  uint64(sws.memberID),\n\t\tRevision:  rev,\n\t\tRaftTerm:  sws.sg.Term(),\n\t}\n}\n\nfunc filterNoDelete(e mvccpb.Event) bool {\n\treturn e.Type == mvccpb.DELETE\n}\n\nfunc filterNoPut(e mvccpb.Event) bool {\n\treturn e.Type == mvccpb.PUT\n}\n\n// FiltersFromRequest returns \"mvcc.FilterFunc\" from a given watch create request.\nfunc FiltersFromRequest(creq *pb.WatchCreateRequest) []mvcc.FilterFunc {\n\tfilters := make([]mvcc.FilterFunc, 0, len(creq.Filters))\n\tfor _, ft := range creq.Filters {\n\t\tswitch ft {\n\t\tcase pb.WatchCreateRequest_NOPUT:\n\t\t\tfilters = append(filters, filterNoPut)\n\t\tcase pb.WatchCreateRequest_NODELETE:\n\t\t\tfilters = append(filters, filterNoDelete)\n\t\tdefault:\n\t\t}\n\t}\n\treturn filters\n}\n", "numLines": 619, "startLine": 1, "totalLines": 619}}

